 73→    private var mCardType: String? = null
 74→    private var mInitialOrdinalProcessed = false
 75→    protected var previewLayout: PreviewLayout? = null
 76→    override fun onCreate(savedInstanceState: Bundle?) {
 77→        if (showedActivityFailedScreen(savedInstanceState)) {
 78→            return
 79→        }
 80→        super.onCreate(savedInstanceState)
 81→        var parameters = savedInstanceState
 82→        if (parameters == null) {
 83→            parameters = intent.extras
 84→        }
 85→        if (parameters != null) {
 86→            mNoteEditorBundle = parameters.getBundle("noteEditorBundle")
 87→            mEditedModelFileName = parameters.getString(CardTemplateNotetype.INTENT_MODEL_FILENAME)
 88→            mCardList = parameters.getLongArray("cardList")
 89→            mOrdinal = parameters.getInt("ordinal")
 90→            mCardListIndex = parameters.getInt("cardListIndex")
 91→            mShowingAnswer = parameters.getBoolean("showingAnswer", mShowingAnswer)
 92→        }
 93→        if (mEditedModelFileName != null) {
 94→            Timber.d("onCreate() loading edited model from %s", mEditedModelFileName)
 95→            try {
 96→                mEditedNotetype = CardTemplateNotetype.getTempModel(mEditedModelFileName!!)
 97→                mCardType = mEditedNotetype!!.optString("name")
 98→            } catch (e: IOException) {
 99→                Timber.w(e, "Unable to load temp model from file %s", mEditedModelFileName)
100→                closeCardTemplatePreviewer()
101→            }
102→        }
