143→        topBarLayout!!.visibility = View.GONE
144→        findViewById<View>(R.id.answer_options_layout).visibility = View.GONE
145→        findViewById<View>(R.id.bottom_area_layout).visibility = View.VISIBLE
146→        previewLayout = createAndDisplay(this, mToggleAnswerHandler)
147→        previewLayout!!.setOnPreviousCard { onPreviousCard() }
148→        previewLayout!!.setOnNextCard { onNextCard() }
149→        previewLayout!!.hideNavigationButtons()
