184→    /** When the next template is requested  */
185→    fun onNextCard() {
186→        var index = cardIndex
187→        if (!isNextBtnEnabled(index)) {
188→            return
189→        }
190→        cardIndex = ++index
191→        onCardIndexChanged()
192→    }
