234→    override fun onCollectionLoaded(col: Collection) {
235→        super.onCollectionLoaded(col)
236→        if (mNoteEditorBundle != null) {
237→            mAllFieldsNull = false
238→            // loading from the note editor
239→            val toPreview = setCurrentCardFromNoteEditorBundle(col)
240→            if (toPreview != null) {
241→                cardCount = toPreview.note().numberOfCardsEphemeral()
242→                if (cardCount >= 2) {
243→                    previewLayout!!.showNavigationButtons()
244→                }
245→            }
246→        } else {
247→            // loading from the card template editor
248→            mAllFieldsNull = true
