250→            if (mCardList != null && mCardListIndex >= 0 && mCardListIndex < mCardList!!.size) {
251→                currentCard = PreviewerCard(col, mCardList!![mCardListIndex])
252→            } else if (mEditedNotetype != null) { // bare note type (not coming from note editor), or new card template
253→                Timber.d("onCreate() CardTemplatePreviewer started with edited model and template index, displaying blank to preview formatting")
254→                currentCard = getDummyCard(mEditedNotetype!!, mOrdinal)
255→                if (currentCard == null) {
256→                    showThemedToast(applicationContext, getString(R.string.invalid_template), false)
