307→    /**
308→     * Set the set tags of currentNote to tagsList.  We make no
309→     * assumption on the content of tagsList, except that its strings
310→     * are valid tags (i.e. no spaces in it).
311→     */
312→    private fun setTags(currentNote: Note, tagsList: List<String>?) {
313→        val currentTags = currentNote.tags.toTypedArray()
314→        for (tag in currentTags) {
315→            currentNote.delTag(tag)
316→        }
317→        if (tagsList != null) {
318→            val tagsSet = currentNote.col.tags.canonify(tagsList)
