332→    private fun getBundleEditFields(noteEditorBundle: Bundle?): MutableList<String> {
333→        val noteFields = noteEditorBundle!!.getBundle("editFields")
334→            ?: return mutableListOf()
335→        // we map from "int" -> field, but the order isn't guaranteed, and there may be skips.
336→        // so convert this to a list of strings, with null in place of the invalid fields
337→        val elementCount = noteFields.keySet().stream().map { s: String -> s.toInt() }.max { obj: Int, anotherInteger: Int? -> obj.compareTo(anotherInteger!!) }.orElse(-1) + 1
338→        val ret = Array(elementCount) { "" } // init array, nulls cause a crash
339→        for (fieldOrd in noteFields.keySet()) {
340→            ret[fieldOrd.toInt()] = noteFields.getString(fieldOrd)!!
341→        }
342→        return mutableListOf(*ret)
