396→    private fun calculateIndexFromOrdinal(note: Note, ordinal: Int): Int {
397→        if (note.notetype.isCloze) {
398→            val clozeOrds = note.getSortedClozeNumbers()
399→            for (i in clozeOrds.indices) {
400→                if (clozeOrds[i] - 1 == ordinal) {
401→                    return i
402→                }
403→            }
404→            return 0
405→        } else {
406→            return ordinal
407→        }
