411→    inner class PreviewerCard : Card {
412→        private val mNote: Note?
413→
414→        constructor(col: Collection, id: Long) : super(col, id) {
415→            mNote = null
416→        }
417→
418→        /* if we have an unsaved note saved, use it instead of a collection lookup */ override fun note(
419→            reload: Boolean
420→        ): Note {
421→            return mNote ?: super.note(reload)
422→        }
