424→        /** if we have an unsaved note saved, use it instead of a collection lookup  */
425→        override fun note(): Note {
426→            return mNote ?: super.note()
427→        }
428→
429→        /** if we have an unsaved note, never return empty  */
430→        val isEmpty: Boolean
431→            get() = mNote != null
432→
433→        /** Override the method that fetches the model so we can render unsaved models  */
434→        override fun model(): NotetypeJson {
435→            return mEditedNotetype ?: super.model()
436→        }
437→
438→        override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
439→            if (renderOutput == null || reload) {
440→                val index = if (model().isCloze) {
441→                    0
442→                } else {
443→                    ord
444→                }
445→                val context = TemplateManager.TemplateRenderContext.fromCardLayout(
446→                    note(),
447→                    this,
448→                    model(),
449→                    model().getJSONArray("tmpls")[index] as JSONObject,
450→                    fillEmpty = false
451→                )
452→                renderOutput =
453→                    context.render()
454→            }
455→            return renderOutput!!
456→        }
457→    }
