460→private class EphemeralCard(col: Collection, id: Long?) : Card(col, id) {
461→    override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
462→        return this.renderOutput!!
463→    }
464→    companion object {
465→        fun fromNote(n: Note, col: Collection, cardIndex: Int = 0): EphemeralCard {
466→            val card = EphemeralCard(col, null)
467→            card.did = 1
468→            card.ord = n.cardIndexToOrd(cardIndex)
469→
470→            val nt = n.notetype
471→            val templateIdx = if (nt.type == Consts.MODEL_CLOZE) {
472→                0
473→            } else {
474→                cardIndex
475→            }
476→            val template = nt.tmpls[templateIdx] as JSONObject
477→            template.put("ord", card.ord)
478→
479→            val output = TemplateManager.TemplateRenderContext.fromCardLayout(
480→                n,
481→                card,
482→                notetype = nt,
483→                template = template,
484→                fillEmpty = false
485→            ).render()
486→            card.renderOutput = output
487→            card.setNote(n)
488→            return card
489→        }
490→    }
491→}
