494→private fun Note.numberOfCardsEphemeral(): Int {
495→    // We can't use note.numberOfCards() as this uses the database value
496→    return when {
497→        this.notetype.isCloze -> col.clozeNumbersInNote(this).size
498→        else -> notetype.templatesNames.size
499→    }
