private fun Note.numberOfCardsEphemeral(): Int {
    // We can't use note.numberOfCards() as this uses the database value
    return when {
        this.notetype.isCloze -> col.clozeNumbersInNote(this).size
        else -> notetype.templatesNames.size
    }
}

